     4	namespace InventoryFlow.Domain.Entities;
     5	
     6	/// <summary>
     7	/// Represents a hashed refresh token issued to an authenticated user.
     8	/// </summary>
     9	public sealed class RefreshToken : Entity<Guid>
    10	{
    11	    /// <summary>
    12	    /// Initializes a new instance of the <see cref="RefreshToken"/> class.
    13	    /// </summary>
    14	    /// <param name="id">The refresh-token identifier.</param>
    15	    /// <param name="userId">The identifier of the token owner.</param>
    16	    /// <param name="tokenHash">The one-way hash of the issued refresh token.</param>
    17	    /// <param name="expiresAtUtc">The UTC instant after which the token cannot be used.</param>
    18	    /// <exception cref="DomainException">Thrown when an identifier or token hash is empty, or the expiration is not UTC.</exception>
    19	    public RefreshToken(
    20	        Guid id,
    21	        Guid userId,
    22	        string tokenHash,
    23	        DateTimeOffset expiresAtUtc)
    24	        : base(id)
    25	    {
    26	        if (id == Guid.Empty)
    27	        {
    28	            throw new DomainException("Refresh token identifier is required.");
    29	        }
    30	
    31	        if (userId == Guid.Empty)
    32	        {
    33	            throw new DomainException("Refresh token user identifier is required.");
    34	        }
    35	
    36	        if (string.IsNullOrWhiteSpace(tokenHash))
    37	        {
    38	            throw new DomainException("Refresh token hash is required.");
    39	        }
    40	
    41	        if (expiresAtUtc.Offset != TimeSpan.Zero)
    42	        {
    43	            throw new DomainException("Refresh token expiration must be in UTC.");
    44	        }
    45	
    46	        UserId = userId;
    47	        TokenHash = tokenHash;
    48	        ExpiresAtUtc = expiresAtUtc;
    49	    }
    50	
    51	    /// <summary>
    52	    /// Gets the identifier of the user that owns this token.
    53	    /// </summary>
    54	    public Guid UserId { get; private set; }
    55	
    56	    /// <summary>
    57	    /// Gets the one-way hash of the issued token.
    58	    /// </summary>
    59	    public string TokenHash { get; private set; }
    60	
    61	    /// <summary>
    62	    /// Gets the UTC instant at which this token expires.
    63	    /// </summary>
    64	    public DateTimeOffset ExpiresAtUtc { get; private set; }
    65	
    66	    /// <summary>
    67	    /// Gets the UTC instant at which this token was revoked, if applicable.
    68	    /// </summary>
    69	    public DateTimeOffset? RevokedAtUtc { get; private set; }
    70	
    71	    /// <summary>
    72	    /// Gets a value indicating whether this token is valid at the supplied UTC instant.
    73	    /// </summary>
    74	    /// <param name="utcNow">The current UTC instant.</param>
    75	    /// <returns><see langword="true"/> when the token is unrevoked and unexpired; otherwise, <see langword="false"/>.</returns>
    76	    public bool IsActive(DateTimeOffset utcNow) =>
    77	        RevokedAtUtc is null && ExpiresAtUtc > utcNow;
    78	
    79	    /// <summary>
    80	    /// Revokes this token at the supplied UTC instant.
    81	    /// </summary>
    82	    /// <param name="revokedAtUtc">The UTC instant at which the token was revoked.</param>
    83	    /// <exception cref="DomainException">Thrown when the supplied instant is not UTC.</exception>
    84	    public void Revoke(DateTimeOffset revokedAtUtc)
    85	    {
    86	        if (revokedAtUtc.Offset != TimeSpan.Zero)
    87	        {
    88	            throw new DomainException("Refresh token revocation time must be in UTC.");
    89	        }
    90	
    91	        RevokedAtUtc ??= revokedAtUtc;
    92	    }
    93	}
