     9	namespace InventoryFlow.Infrastructure.DependencyInjection;
    10	
    11	/// <summary>
    12	/// Registers infrastructure-layer services.
    13	/// </summary>
    14	public static class InfrastructureServiceCollectionExtensions
    15	{
    16	    /// <summary>
    17	    /// Adds SQL Server persistence and ASP.NET Core Identity services.
    18	    /// </summary>
    19	    /// <param name="services">The dependency-injection service collection.</param>
    20	    /// <param name="configuration">The application configuration.</param>
    21	    /// <returns>The supplied <paramref name="services"/> instance.</returns>
    22	    /// <exception cref="ArgumentException">Thrown when the database connection string is missing.</exception>
    23	    public static IServiceCollection AddInfrastructure(
    24	        this IServiceCollection services,
    25	        IConfiguration configuration)
    26	    {
    27	        ArgumentNullException.ThrowIfNull(services);
    28	        ArgumentNullException.ThrowIfNull(configuration);
    29	
    30	        var connectionString = configuration.GetConnectionString("InventoryFlowDatabase");
    31	        ArgumentException.ThrowIfNullOrWhiteSpace(
    32	            connectionString,
    33	            "ConnectionStrings:InventoryFlowDatabase");
    34	
    35	        services.AddDbContext<ApplicationDbContext>(options => options.UseSqlServer(
    36	            connectionString,
    37	            sqlServerOptions => sqlServerOptions.EnableRetryOnFailure()));
    38	        services.AddDataProtection()
    39	            .SetApplicationName("InventoryFlow")
    40	            .PersistKeysToDbContext<ApplicationDbContext>();
    41	
    42	        services.AddIdentityCore<ApplicationUser>(options =>
    43	            {
    44	                options.User.RequireUniqueEmail = true;
    45	                options.Password.RequiredLength = 12;
    46	                options.Password.RequireDigit = true;
    47	                options.Password.RequireLowercase = true;
    48	                options.Password.RequireUppercase = true;
    49	                options.Password.RequireNonAlphanumeric = true;
    50	                options.Lockout.AllowedForNewUsers = true;
    51	                options.Lockout.DefaultLockoutTimeSpan = TimeSpan.FromMinutes(15);
    52	                options.Lockout.MaxFailedAccessAttempts = 5;
    53	            })
    54	            .AddRoles<IdentityRole<Guid>>()
    55	            .AddEntityFrameworkStores<ApplicationDbContext>()
    56	            .AddSignInManager()
    57	            .AddDefaultTokenProviders();
    58	
    59	        return services;
    60	    }
    61	}
